var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"면회시간은 15분. 규정상 연장은 안됩니다.","JPN":"面会時間は15分。規定上、延長はできません。","ENG":"You have 15 minutes. There will be no extensions.","TWN":"面會時間是15分鐘，規定無法加時。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"요청하신대로 녹음은 되지 않을 테니, 문제가 생기면 언제든 호출벨을 누르십시오.","JPN":"要請どおり録音はしませんので、問題がありましたらいつでも呼び出しのベルを押してください。","ENG":"We won’t be recording your visit, like you requested. Should you need any help, please press the pager.","TWN":"照您的吩咐不會進行錄音，要是有什麼問題請按呼叫鈕。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 배려 감사합니다.","JPN":"はい、お気遣いありがとうございます。","ENG":"Yes, thank you for your kindness.","TWN":"好，謝謝你。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"……면회인이 들어갑니다.","JPN":"……面会人、入ります。","ENG":"...Visitor entering.","TWN":"……請進。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이게 누구십니까? 이런 귀한 분께서 늙은이를 직접 배웅하러 오실 줄이야.","JPN":"これはこれは。尊き方がこの老人のために直接見送りに来てくださるとは。","ENG":"Well, well, well... If it isn’t the great Lady Nanahara herself. Here to bid me farewell?","TWN":"這是誰啊？沒想到會有如此尊貴的人來送我這老頭一程呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"돌이키지 못할 짓을 저지르고서도 태도가 뻔뻔하군요, 하바키.","JPN":"取り返しのつかないことをしておいて図々しいですね、覇吐。","ENG":"How are you so shameless after all the things you have done, Habaki?","TWN":"幅木，你做出這種無法挽回的事，還毫無悔意嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대에겐 죄책감이란 게 없는 건가요?","JPN":"あなたには罪悪感というものがないのですか？","ENG":"Do you not have any remorse in yourself?","TWN":"你難道沒有一絲罪惡感嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"후회라면 하고 있지요.","JPN":"後悔ならしております。","ENG":"As a matter of fact, I do.","TWN":"後悔嗎？當然。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그 노망난 여자와 협력했다가 이 사단이 나고 말았으니 말입니다.","JPN":"あのもうろくした女と協力してこうなってしまいましたからな。","ENG":"I regret cooperating with that damn woman.","TWN":"我後悔跟那個糊塗的女人合作，落得這般下場。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"반성이라곤 없는 자가…… 왜 스스로 관리국에 투항하여 이곳에 갇힌 겁니까?","JPN":"少しの反省もないのに……どうして自ら管理局に投降し、ここに閉じ込められていたのですか？","ENG":"If you do not feel guilty at all... Why did you surrender to the Administration?","TWN":"你根本不懂得反省……又為何要向管理局自首被關在這裡？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저도 제 목숨 귀한 줄은 아는 놈입니다, 당주님.","JPN":"わしも自分の命の大切さはよく知っております、ご当主。","ENG":"I know my life is important, Lady Nanahara.","TWN":"因為我也是很愛惜生命的，堂主。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이 철창이 없었다면 하야미의 여식이 진작에 제 목을 쳤겠지요.","JPN":"この鉄格子がなかったなら、速水家の娘がわしの首を討ち取っていたことでしょう。","ENG":"Without these bars, I would have been long past dead in the hands of that Hayami girl.","TWN":"要不是被關在這裡，我早就去向速水的女兒索命！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇게 고개를 들고서 선조들을 뵐 생각은 않는 게 좋을 겁니다.","JPN":"そのように顔を上げてご先祖様にお会いできると思わない方がいいでしょう。","ENG":"You better not think of joining our ancestors with that arrogance.","TWN":"我看你怎麼和祖先交代。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"지당하신 말씀입니다. 이대로 허무하게 끝나서야 저승에 계신 선조를 볼 면목이 없지요.","JPN":"ごもっともです。このまま虚しく終わっては、冥府のご先祖様に合わす顔がありません。","ENG":"Precisely. I wouldn’t be able to look at my ancestors in the eye in the Afterlife. Not when my work ends in vain.","TWN":"您說的是，就這樣空虛地結束，確實無法對在地獄裡的祖先交代。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"사요가 부럽군요. 오로치와 하나가 되어 선조를 뵐 일조차 없어졌으니.","JPN":"小夜がうらやましい。オロチと一つになり、先祖に会うことすらできなくなりましたからな。","ENG":"I would say that I am quite envious of Sayo, though. She wouldn’t have to worry about facing our ancestors, since she became one with Orochi.","TWN":"真羨慕小夜，和大蛇合而為一後，就不用煩惱怎麼跟祖先交代。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나나하라 사요는 그대가 몰래 저지른 그 끔찍한 만행들을 끝내 알아채지 못 했더군요.","JPN":"七原小夜はあなたが秘密裏に行った恐ろしい蛮行に最後まで気付きませんでした。","ENG":"It seems that Nanahara Sayo never noticed the terrible wrongdoings you’ve been performing behind her back.","TWN":"七原小夜到最後都沒發現你背地裡所做的惡行。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대가 연합 몰래 선대 당주들의 시신을 영지 밖으로 빼돌렸다는 사실을 말이죠.","JPN":"あなたが連合の目を盗んで先代当主の遺体を領地外へ送ったことです。","ENG":"The fact that you smuggled the bodies of the former Head of Nanaharas out of the estate, right under our noses.","TWN":"就是你瞞著聯盟將先祖堂主的屍體移到領地外這件事。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"허허, 벌써 거기까지 알아내시다니 역시 바람의 목소리를 들으시는 분 다우시군요.","JPN":"ほほう、もうそこまでおわかりとは。さすがは風の声を聞くにふさわしい方だ。","ENG":"Ha ha, I must say I am rather impressed. You do hear the voice of wind after all, do you not?","TWN":"呵呵，竟然連這件事都知道，不愧是能聽見風聲的人。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"한 가문의 당주라는 자가…… 어째서 그런 짓을 벌인 건가요?","JPN":"一家の当主たるものが……どうしてそのようなことをしたのですか？","ENG":"You are the head of a family... why would you do something like that?","TWN":"你身為家族的堂主……怎麼能做出這種事？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저는 오래전부터 이해가 되지 않았습니다.","JPN":"わしは昔から理解ができませんでした。","ENG":"I have been pondering for a long time.","TWN":"我從以前就不太明白，"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"나나하라는 어찌하여 기껏 손에 얻은 신의 힘을 더 유용하게 쓰지 못하는가?","JPN":"七原家はせっかく手に入れた神の力をどうしてもっと有効に使わないのか。","ENG":"Why are the Nanaharas incapable of utilizing god’s powers better?","TWN":"為何七原不能更有效地運用好不容易得到手的神力呢？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그 힘의 원리를 파헤치고 이해하려는 노력을 했더라면, 굳이 전통 따위에 연연하지 않아도 더 많은 힘을 이용할 수 있을 텐데 말입니다.","JPN":"その力の原理を暴き理解しようと努力したなら、あえて伝統などにこだわらずともより多くの力を利用することができるはずなのにです。","ENG":"If only you tried to understand the mechanism and look beyond, you could have gotten so much more without your wretched tradition.","TWN":"要是曾經努力研究過那股力量，就不會受限於傳統，而是可以更多發揮這股力量。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그래서, 고작 그런 이유로 당주들을 살해한 건가요?","JPN":"それで、たかがそんな理由で当主たちを殺したのですか？","ENG":"Are you saying that you murdered countless family leaders, just because of that?","TWN":"你就因為這個理由而殺害堂主嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저는 그저 사요가 저지른 짓들의 뒤처리를 도맡으며 도움이 될 만한 것들을 챙겨왔을 뿐입니다.","JPN":"わしはただ小夜がしでかした事の後始末を受け持ちながら、役に立ちそうなものを貰っただけです。","ENG":"I simply took my share of advantages while taking care of Sayo’s dirty work.","TWN":"我只負責替小夜善後，以及預備她所需要的東西。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"폐당주님의 일은 저도 안타깝습니다.","JPN":"亡きご当主のことは残念に思っております。","ENG":"I am deeply sorry about what happened with the former Lady Nanahara.","TWN":"前堂主的事我也很遺憾。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"살아서도 죽어서도 누구에게 변변한 도움도 되지 못한, 실로 딱한 자였지요.","JPN":"生きているときも、死んでさえも、何の役に立つこともできない実に哀れな方でしたな。","ENG":"Such a pitiful being, unable to be of help to anyone... whether dead or alive, that is.","TWN":"無論她是生是死，對任何人都沒有用處，實乃可憐之人。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하바키! 대체 어머니의 몸에 무슨 짓을 저지른 거죠?!","JPN":"覇吐！　いったい母の体に何をしたのですか！？","ENG":"Habaki! What have you done to my mother’s body?!","TWN":"幅木！你到底對媽媽的身體做了什麼！？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"호오……? 당주님께서 모르고 계시는 것도 있었군요.","JPN":"ほう……？　ご当主にも知らないことがあるんですな。","ENG":"Oh...? I see you are not aware of everything that has happened.","TWN":"喔呵……？原來也有堂主您不知道的事嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저는 폐당주님의 시신엔 손가락 하나 대지 않았습니다.","JPN":"亡きご当主の遺体には指一本触れておりません。","ENG":"I did not lay hands on the former Lady Nanahara’s body.","TWN":"我沒有碰前堂主的屍體一根寒毛。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"제가 원하던 것은 무녀의 몸이지, 평범한 인간은 필요하지 않으니까요.","JPN":"欲しかったのは巫女の身体であって、普通の人間は必要ないですからな。","ENG":"What I wanted was the body of a priestess, not an ordinary human being.","TWN":"我要的是巫女的身體，而不是一個再普通不過的平凡人。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"뭐라고요?","JPN":"なんですって？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"모든 나나하라의 직계 후손이 바람의 목소리를 듣는 것은 아닙니다.","JPN":"七原家の直系子孫なら誰でも風の声を聞けるというわけではありません。","ENG":"Not every direct descendant of the Nanahara family is capable of listening to the voice of wind.","TWN":"並非所有七原的直系後裔都聽得到風聲。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그런데, 당주님의 어머니께선 잘도 모두를 속이고 당주의 자리에 오르셨더군요.","JPN":"ところが、ご当主のお母上はみんなを騙して当主になりました。","ENG":"However, your mother had swindled her way into becoming the head, deceiving everyone around her.","TWN":"但您的母親卻欺騙大家坐上堂主之位。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어머니께서…… 다른 분들을 속이셨다고? 그게 무슨?","JPN":"お母様が……他の方を騙した？　それはどういう？","ENG":"My mother... deceived everyone? What do you mean?","TWN":"你說媽媽她……欺騙大家？這是什麼意思？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"말 그대로입니다.","JPN":"言葉どおりの意味です。","ENG":"Oh, I think you know what I mean.","TWN":"就是字面上的意思。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"바람의 목소리를 듣지 못하는 무녀가 당주의 권한을 얻기 위해 그 자리에 오른 것이지요.","JPN":"風の声を聞けない巫女が当主の権限を得るためにその地位に就いたのです。","ENG":"A priestess incapable of hearing the voice of wind, becoming the Head of Nanahara? For power?","TWN":"聽不到風聲巫女，因為覬覦堂主的權力而坐上那個位置。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그래서 사요는 폐당주를 오로치에게 바쳤음에도, 아무런 성과를 얻지 못했습니다.","JPN":"ですから、小夜は亡き当主をオロチに捧げたのにもかかわらず、なんの成果も得られなかったのです。","ENG":"That is the reason why Sayo failed to reach her goals, even when she offered the former Lady Nanahara to Orochi.","TWN":"所以就算小夜將前堂主獻給大蛇，也不會有任何結果的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이래서야…… 당주가 되려고 역신의 목소리를 빌린 악인과 다를 바 없지 않겠습니까?","JPN":"これでは……当主になろうと疫病神の威を借りた悪人と大差ありませんな？","ENG":"Not so different from the traitor who tried using the Plague God to become the head, is she?","TWN":"這麼看來……她和想當上堂主而借助瘟神之聲的惡人又有何異？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하바키! 감히 그대가 어머니마저 모욕할 셈인 건가요!","JPN":"覇吐！　あなたはお母様まで侮辱するつもりですか！","ENG":"Habaki! How dare you insult my mother?!","TWN":"幅木！你竟敢出言侮辱媽媽！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"하하하!","JPN":"ハハハ！","ENG":"Ha ha ha!","TWN":"哈哈哈！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"감정에 휘둘리지 마십시오, 당주님.","JPN":"感情に振り回されますな、ご当主。","ENG":"Do not be swayed by emotions, my lady.","TWN":"堂主，請勿感情用事。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"사요가 역신의 힘에 매료되어 가문의 피로 손을 더럽히는 동안, 저희는 오랫동안 신의 힘을 연구하며 초대 당주가 예지한 종말에 대적할 방법을 찾아왔습니다.","JPN":"小夜が疫病神の力に魅了され家門の血で手を汚している間、我々は長い時間をかけ神の力を研究し、初代当主が予知した終焉に立ち向かう方法を模索してきました。","ENG":"While Sayo was busy shedding blood with the Plague God’s powers, we have been studying god’s powers for a long time... in search of a way to prevent the apocalypse that the first Lady Nanahara predicted.","TWN":"在小夜受到瘟神力量的迷惑，以家族的血弄髒自己的手的同時，我們一直在研究神力，並且針對初代堂主預言的結局尋找對策。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그런데 신의 힘을 물려받은 당주님께선 어떻습니까?","JPN":"ところが神の力を受け継いだご当主はといえばどうでしょうか？","ENG":"Then, there is you, Lady Chinatsu.","TWN":"那繼承神力的您又如何呢？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"망령 든 목소리에만 매달리는 자들의 우두머리가 되어 주어진 운명에 따르기 급급하지요.","JPN":"神懸かった声にばかり頼りきっている者たちの上に立ち、与えられた運命に従うのが精一杯。","ENG":"You are gifted with god’s powers, yet you allow yourself to get dragged by fools and the whims of destiny... All of you, fixated on a mere illusionary voice.","TWN":"聽信讒言替他們出頭，迫不及待要順從既定的命運。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그런 식으로는 아무것도 바꿀 수 없다는 걸, 아직도 모른다고 하진 않으시겠지요?","JPN":"それでは何も変えられないということは、ご当主もすでにおわかりではないですか？","ENG":"Surely you must know by now that you cannot make any change with that pathetic attitude.","TWN":"這樣根本無法改變任何事，您該不會現在還不知道吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"만용과 과신이 그대의 죄를 가려주진 못할 겁니다!","JPN":"あなたの罪は蛮勇や過信という言葉でもごまかせません！","ENG":"Pretense and arrogance won't wash away your sins!","TWN":"匹夫之勇並無法遮掩你犯罪的事實！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그렇다면 당주님의 계획은 어떠십니까?","JPN":"でしたらご当主の計画はいかがですかな？","ENG":"Elaborate on your plans, my lady.","TWN":"那麼堂主的計畫是什麼？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이 땅에 역신이 다시 한번 깨어났을 때, 그것을 막기 위해 어떤 희생을 치르실 것인지요?","JPN":"この地に疫病神が再び目を覚ました時、それを止めるためにどのような犠牲を払うおつもりか。","ENG":"When the Plague God awakens on this earth once more, what will you sacrifice to stop it?","TWN":"當瘟神再次於這塊土地上甦醒時，您打算做出什麼樣的犧牲來阻止？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 더 이상…… 운명을 빌미로 누군가를 희생시키지 않기로 했어요.","JPN":"私はもう……運命を言い訳に誰かを犠牲にしないと決めました。","ENG":"I... have made a decision to make no further sacrifices.","TWN":"我已經決定……再也不會假借命運之名而犧牲任何人。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"운명은 의지로 극복해 나갈 수 있는 것이라고, 이제는 그렇게 믿고 있으니까요.","JPN":"運命は意志の力で乗り越えられるものだと、今はそう信じていますから。","ENG":"I now believe that fate can be conquered with will.","TWN":"因為我現在相信，命運是可以靠意志力勝過的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"허허, 변하셨군요. 한때 누구보다 자신을 희생하고자 하셨던 분께서 말을 바꾸실 줄이야.","JPN":"ほほう、変わりましたな。かつて誰よりも自らを犠牲にしようとした方がその考えを変えるとは。","ENG":"Ha ha, you have changed. Hearing from someone who once tried to sacrifice herself over anything else...","TWN":"呵呵，人果然是會變的呢，以前的您總是說要犧牲自己。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"막상 죽음이 코앞에 닥쳐오니 두려워지신 겁니까?","JPN":"いざ死が目前に迫ってきたので恐れをなしましたかな？","ENG":"Are you afraid, now that death has come upon you?","TWN":"因為當死亡來臨時，您還是會感到害怕是嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대 같은 사람은 죽는 순간까지도 이해하지 못할 것입니다.","JPN":"あなたのような人は死ぬ間際になっても理解できないでしょう。","ENG":"People like you will never understand. Not even in the brink of death.","TWN":"像你這種人，到死前那一刻都不會明白的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"또한 그대의 이해를 바라지도 않습니다.","JPN":"それに、あなたが理解してくれることを望んでもいません。","ENG":"I do not expect you to.","TWN":"另外，我也不希望你會理解。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"희생 없이 얻는 건 아무것도 없는 법.","JPN":"犠牲なくしては得るものもない。","ENG":"There is no gain without sacrifice.","TWN":"沒有犧牲就沒有收穫。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"당주님께서 원하시건 원치 않건, 자신의 생각이 틀렸다는 사실을 결국 깨닫게 되실 겁니다.","JPN":"ご当主が望もうが望むまいが、ご自身の考えが違っていたということに最後には気付くことでしょう。","ENG":"You will come to realize that, whether you want to or not.","TWN":"無論您願不願意，您最後終究會發現自己的想法是錯的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……수확은 있으셨습니까?","JPN":"……収穫はありましたか？","ENG":"...How did it go?","TWN":"……有收穫嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하바키가 시신을 빼돌린 것은 그 안에 깃든 신의 힘을 연구하기 위해서였습니다.","JPN":"覇吐が遺体を横流ししたのは、その中に宿った神の力を研究するためでした。","ENG":"The reason Habaki smuggled the bodies was to study god’s power vested within them.","TWN":"幅木之所以偷走屍體，是因為要研究在屍體內的神力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리곤 자신의 업적을 자랑스럽게 늘어놓더군요.","JPN":"そして自分の業績を自慢していました。","ENG":"He started to boast off his so called \\"achievements\\".","TWN":"而且他對自己的行為感到非常自豪。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희…… 라는 표현을 쓰면서요.","JPN":"我々……という表現を使いながら。","ENG":"Using the word, \\"we\\"...","TWN":"我們……他是這麼說的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇다면 외부에 협력자가 있다는 사실은 이걸로 확실해졌군요.","JPN":"外部に協力者がいることがこれで明確になりましたね。","ENG":"So, it is true that he had help from the outside.","TWN":"這麼說來，應該就可以確定他在外面有幫手。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키가 이송될 때까지 감시역을 붙여 두겠습니다.","JPN":"覇吐が移送されるまで監視を付けておきます。","ENG":"I will put someone to watch over him until he gets imprisoned.","TWN":"在幅木移送前，我會派人監視他。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미안해요. 제 능력이 모자란 탓에…… 이런 일 밖에 하지 못해서.","JPN":"ごめんなさい。私の能力不足のせいで……こんなことしかできなくて。","ENG":"My apologies. This is all because I lack capability... I cannot do anything else...","TWN":"對不起，都怪我沒用……只能幫上這點忙。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그런 말씀 마십시오. 선조들을 욕보인 자 앞에 당주님을 내세워야만 했던 저의 책임입니다.","JPN":"そんなことおっしゃらないでください。ご先祖様を侮辱した者と対するのにご当主様を頼ることしかできない私の責任です。","ENG":"Please refrain. It is my responsibility for letting you take the blame from someone who is insulting our tradition.","TWN":"堂主別這麼說，要怪就怪我，必須讓堂主去面對侮辱祖先之人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……하바키는 가문을 속이고 배반한 자입니다. 거짓이 섞여 있을 가능성도 있겠죠.","JPN":"……覇吐は家門を騙した裏切り者です。嘘を言っている可能性もあるでしょう。","ENG":"...Habaki deceived and betrayed us. There is a possibility that he might have stated falsely.","TWN":"……不過幅木畢竟是欺騙家族的叛徒，不能完全相信他的話。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하지만 그 자의 말이 사실이라면, 지금까지의 정황은 모두 맞아떨어집니다.","JPN":"ですがもしあの者の話が本当なら、今までの状況とすべて一致します。","ENG":"But if what he said is true, everything adds up.","TWN":"不過若他所言屬實，那和目前所有的情況就是吻合的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키 당주가 선조들의 영묘에 손을 댄 이유와…… 사요 장로가 전대당주님을 해하였음에도 오로치를 깨우지 못한 이유도 말이지요.","JPN":"覇吐当主がご先祖様の霊廟に手を出した理由……それと、小夜長老が先代当主を害することまでしても、オロチを呼び覚ませなかった理由。","ENG":"The reason why Habaki meddled with the tombs of our ancestors... and why Sayo failed to awaken Orochi, even when she harmed the former Lady Nanahara.","TWN":"幅木堂主盜取祖先屍體的原因……和小夜長老殺害堂主也無法喚醒大蛇的原因。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사나에…….","JPN":"早苗……","ENG":"Sanae...","TWN":"早苗……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어머니께선 정말로……. 사람들을 모두 속이고 당주의 자리에 오르셨던 걸까요?","JPN":"お母様は本当に……皆を騙して当主になったのでしょうか。","ENG":"Do you really think... that my mother deceived everyone to become the head of our family?","TWN":"媽媽她真的……欺騙眾人坐上堂主的位置嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제가 아는 전대당주님은 악의를 품고 남을 속이는 분이 아니셨습니다.","JPN":"私の知る先代当主は悪意を持って人を騙すような方ではありませんでした。","ENG":"The former Lady Nanahara was not someone who would trick others with malice.","TWN":"我認識的前任堂主不是會惡意欺騙他人之人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"연합의 괄시를 받던 하야미 가문 사람에게 온정을 베풀어 준 저의 은인이시기도 하지요.","JPN":"連合にないがしろにされていた速水家の者に温かく接してくださった、私の恩人でもあります。","ENG":"She is my savior, accepting me when everyone else in the Alliance treated the Hayami family with detest.","TWN":"她是我的恩人，在我受到聯盟的輕視時，她卻不曾對我惡言相向。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……저는 아직도 제가 낯설어요.","JPN":"……私はいまだに自分が自分でないような気がします。","ENG":"...I am still not used to myself like this.","TWN":"……現在的我好陌生。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"바람의 목소리 없이는 누구의 마음도 이해하지 못하니, 선뜻 남의 진의를 의심부터 하게 되는 제 자신이 한심하기만 합니다.","JPN":"風の声なしでは誰の心も理解できないので、すぐに人を疑いの目で見てしまう自分が情けないばかりです。","ENG":"Without the voice of wind, I cannot read through people at all. I feel ashamed at myself for doubting everyone.","TWN":"聽不到風聲後，就無法理解人的心，還懷疑別人的話，我對自己感到很失望。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"사실 바람의 목소리를 중도에 잃게 된 무녀는 당주님이 처음이 아닙니다.","JPN":"実は風の声を途中で失ってしまった巫女はご当主様が初めてではございません。","ENG":"Frankly speaking, you are not the first priestess to lose the voice of wind during her tenure.","TWN":"其實，堂主不是第一個失去風聲的巫女。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네……? 그게 갑자기 무슨 말씀이시죠?","JPN":"え……？　急に何をおっしゃるのですか？","ENG":"What...? What do you mean by that?","TWN":"什麼……？你怎麼突然這麼說？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"운명을 모른 채로 받아들이는 것과, 알고 대비하는 것은 다른 법.","JPN":"運命を知らぬまま受け入れることと、知って備えることとは違うものです。","ENG":"For there is a difference between accepting fate unknowingly, and being aware of it and preparing for it...","TWN":"差別在於，一個是在不知情的情況下接受，一個是知道後加以防範。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"전대당주님께선 비밀로 부탁하셨으나…….","JPN":"先代当主は内密にとおっしゃいましたが……","ENG":"The former Lady Nanahara bid me keep it a secret, however...","TWN":"前任堂主拜託我不要說出來的……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이제는 진실을 말씀드릴 때가 된 것 같군요.","JPN":"真実を話す時が来たようですね。","ENG":"I feel that it is time that you discovered the truth, my lady.","TWN":"但現在似乎是該說出真相的時候。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 모르는…… 진실이라고요?","JPN":"私の知らない……真実？","ENG":"The truth...?","TWN":"我不知道的……真相嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"대신 지금부터 듣는 이야기는……. 부디 치후유님에겐 비밀로 해주십시오.","JPN":"その代わり、今からお聞きになることは……どうか千冬様にはご内密にお願いいたします。","ENG":"What you are about to hear... I beg you to keep it hidden from Miss Chifuyu.","TWN":"但我有個條件……接下來您聽到的內容請務必對千冬保密。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};